table.sort(Pokedex_Pokemons, function(a, b)
	return a.Id < b.Id
end)

Pokedex_PokemonsByName = {}

for index, pokemonInfo in pairs(Pokedex_Pokemons) do
	Pokedex_Pokemons[index].Name_Lower = pokemonInfo.Name:lower()
	Pokedex_Pokemons[index].FormatedId = string.format("%03d", pokemonInfo.Id)
	Pokedex_PokemonsByName[Pokedex_Pokemons[index].Name_Lower] = Pokedex_Pokemons[index]
end
